const now = new Date();
const items = $input.all();
const recalls = [];

// Recall intervals by service type (in months)
const recallIntervals = {
  'prophy': 6, 'cleaning': 6, 'prophylaxis': 6,
  'exam': 12, 'checkup': 12, 'annual_exam': 12,
  'srp': 3, 'deep_cleaning': 3, 'perio_maintenance': 3,
  'fluoride': 6, 'sealant': 12,
  'x-ray': 12, 'panoramic': 36, 'bitewing': 12,
  'default': 6
};

for (const item of items) {
  const patient = item.json;
  if (!patient.last_visit_date || !patient.patient_phone) continue;
  if (patient.recall_opt_out === 'yes' || patient.status === 'inactive') continue;

  const lastVisit = new Date(patient.last_visit_date);
  if (isNaN(lastVisit.getTime())) continue;

  const lastService = (patient.last_service || 'default').toLowerCase();
  const intervalMonths = recallIntervals[lastService] || recallIntervals['default'];

  // Calculate when recall is due
  const recallDue = new Date(lastVisit);
  recallDue.setMonth(recallDue.getMonth() + intervalMonths);

  // Check if recall is due (within the next 2 weeks or already overdue)
  const daysUntilDue = (recallDue - now) / (1000 * 60 * 60 * 24);

  if (daysUntilDue <= 14) {
    const monthsSinceVisit = Math.floor((now - lastVisit) / (1000 * 60 * 60 * 24 * 30));
    const isOverdue = daysUntilDue < 0;
    const overdueMonths = isOverdue ? Math.abs(Math.floor(daysUntilDue / 30)) : 0;

    // Skip if recall already sent within last 30 days
    if (patient.last_recall_sent) {
      const lastRecall = new Date(patient.last_recall_sent);
      const daysSinceRecall = (now - lastRecall) / (1000 * 60 * 60 * 24);
      if (daysSinceRecall < 30) continue;
    }

    let smsMsg, voiceMsg;
    if (isOverdue) {
      smsMsg = `Hi ${patient.patient_name}! It's been ${monthsSinceVisit} months since your last dental visit. You're overdue for your ${lastService} appointment. Regular dental care is important for your health! Reply BOOK to schedule, or call us anytime.`;
      voiceMsg = `Hello ${patient.patient_name}, this is a friendly recall from your dental clinic. It has been ${monthsSinceVisit} months since your last visit and you are overdue for your ${lastService} appointment. We recommend scheduling soon to maintain your oral health. Press 1 to book an appointment now, or press 2 to receive a text with our booking information.`;
    } else {
      smsMsg = `Hi ${patient.patient_name}! Your ${lastService} appointment is coming due soon. It's been ${monthsSinceVisit} months since your last visit. Reply BOOK to schedule, or call us!`;
      voiceMsg = `Hello ${patient.patient_name}, this is your dental clinic calling with a friendly reminder. Your ${lastService} appointment is coming due soon. Press 1 to book an appointment, or press 2 to receive scheduling information by text.`;
    }

    recalls.push({
      json: {
        ...patient,
        recall_type: isOverdue ? 'overdue' : 'upcoming',
        months_since_visit: monthsSinceVisit,
        overdue_months: overdueMonths,
        recall_due_date: recallDue.toISOString(),
        last_service: lastService,
        sms_message: smsMsg,
        voice_message: voiceMsg
      }
    });
  }
}

if (recalls.length === 0) {
  return [{ json: { no_recalls: true, count: 0 } }];
}

return recalls;
